class Solution {
public:
    long long minimumSteps(string s) {
        long long steps = 0;
        int left = 0;
        for (int right = 0; right < s.length(); right++) {
            if (s[right] == '1') {
                if (left < right) {
                    steps += right - left;
                }
                left++;
            }
        }
        return steps;
    }
};
```

